#[no_mangle]
pub extern "C" fn ldexp_q2(mut y: f32, mut exp_q2: i32) -> f32 {
    // Keep the exact behavior of the original C2Rust:
    // - Always execute at least one iteration (do-while style)
    // - Use the same step selection and termination condition (break when exp_q2 <= 0)
    static g_expfrac: [f32; 4] = [
        9.313_226e-10_f32,
        7.831_458e-10_f32,
        6.585_445e-10_f32,
        5.537_677e-10_f32,
    ];

    loop {
        let e: i32 = if 30 * 4 > exp_q2 { exp_q2 } else { 30 * 4 };
        let frac = g_expfrac[(e & 3) as usize];
        let scale = ((1_i32 << 30) >> (e >> 2)) as f32;
        y *= frac * scale;

        exp_q2 -= e;
        if exp_q2 <= 0 {
            break;
        }
    }

    y
}
